import sys

MOD = 10**9 + 7

def matrix_mult(A, B):
    n = len(A)
    result = [[0] * n for _ in range(n)]
    for i in range(n):
        for k in range(n):
            if A[i][k] == 0:
                continue
            for j in range(n):
                result[i][j] = (result[i][j] + A[i][k] * B[k][j]) % MOD
    return result

def matrix_pow(mat, power):
    n = len(mat)
    result = [[0] * n for _ in range(n)]
    for i in range(n):
        result[i][i] = 1
    while power > 0:
        if power % 2 == 1:
            result = matrix_mult(result, mat)
        mat = matrix_mult(mat, mat)
        power //= 2
    return result

def main():
    N, M = map(int, sys.stdin.readline().split())
    if M == 1:
        print(1 % MOD)
        return
    mat = [[0] * M for _ in range(M)]
    mat[0][0] = 1
    mat[M-1][0] = 1
    for i in range(M-1):
        mat[i][i+1] = 1
    mat_pow = matrix_pow(mat, N)
    res = mat_pow[M-1][0] % MOD
    print(res)

if __name__ == "__main__":
    main()
